import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../../services/axios';

function ManageEvents() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => { fetchEvents(); }, []);

  const fetchEvents = async () => {
    try {
      const res = await API.get('/events');
      setEvents(res.data.events || []);
    } catch {
      setError('Failed to load events');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id, name) => {
    if (!window.confirm(`Delete "${name}"?`)) return;
    try {
      await API.delete(`/events/${id}`);
      setEvents(events.filter(e => e._id !== id));
    } catch {
      alert('Failed to delete event');
    }
  };

  if (loading) return (
    <div className="flex items-center justify-center min-h-screen">
      <div className="text-center"><div className="text-5xl mb-4 animate-bounce">📝</div>
        <p className="text-gray-500">Loading events...</p></div>
    </div>
  );

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-800">Manage Events</h1>
          <p className="text-gray-500 mt-1">{events.length} events total</p>
        </div>
        <Link to="/admin/create-event"
          className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-6 py-3 rounded-xl font-semibold hover:shadow-lg transition">
          ➕ Create Event
        </Link>
      </div>

      {error && <div className="bg-red-50 text-red-700 px-4 py-3 rounded-xl mb-6">⚠️ {error}</div>}

      {events.length === 0 ? (
        <div className="bg-white rounded-2xl shadow-sm p-16 text-center">
          <div className="text-6xl mb-4">📭</div>
          <h2 className="text-2xl font-bold text-gray-800 mb-2">No Events Yet</h2>
          <p className="text-gray-500 mb-6">Create your first event to get started!</p>
          <Link to="/admin/create-event" className="bg-blue-600 text-white px-6 py-3 rounded-xl hover:bg-blue-700 transition">
            Create Event
          </Link>
        </div>
      ) : (
        <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-6">
          {events.map((event) => (
            <div key={event._id} className="bg-white rounded-2xl shadow-sm overflow-hidden hover:shadow-md transition">
              <img src={event.image || 'https://via.placeholder.com/400x200?text=Event'}
                alt={event.name} className="w-full h-44 object-cover" />
              <div className="p-5">
                <div className="flex justify-between items-start mb-2">
                  <span className="bg-blue-100 text-blue-600 text-xs font-semibold px-3 py-1 rounded-full">{event.category}</span>
                  <span className={`text-xs font-semibold px-3 py-1 rounded-full ${
                    event.status === 'upcoming' ? 'bg-green-100 text-green-700' :
                    event.status === 'cancelled' ? 'bg-red-100 text-red-700' : 'bg-gray-100 text-gray-700'}`}>
                    {event.status}
                  </span>
                </div>
                <h3 className="text-lg font-bold text-gray-800 mb-3 line-clamp-1">{event.name}</h3>
                <div className="space-y-1 text-sm text-gray-500 mb-4">
                  <p>📅 {new Date(event.date).toLocaleDateString()} • {event.time}</p>
                  <p>📍 {event.venue}</p>
                  <p>🎫 {event.availableSeats}/{event.totalSeats} seats • <span className="text-blue-600 font-bold">₹{event.price}</span></p>
                </div>
                <div className="flex gap-2">
                  <Link to={`/admin/edit-event/${event._id}`}
                    className="flex-1 bg-blue-50 text-blue-600 text-center py-2 rounded-xl hover:bg-blue-100 transition font-medium text-sm">
                    ✏️ Edit
                  </Link>
                  <button onClick={() => handleDelete(event._id, event.name)}
                    className="flex-1 bg-red-50 text-red-600 py-2 rounded-xl hover:bg-red-100 transition font-medium text-sm">
                    🗑️ Delete
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default ManageEvents;
